!( function ( $ ) {

    'use strict';

    var widget3DCarousel = function ( $scope ) {

        var $wrapper = $scope.find( '.elematic-3d-carousel' );
        if ( ! $wrapper.length ) return;

        var settings  = $wrapper.data( 'settings' ) || {};
        var $track    = $wrapper.find( '.e3dc-track' );
        var cards     = Array.from( $wrapper.find( '.e3dc-card' ) );
        var numCards  = cards.length;

        if ( numCards < 2 ) return;

        var cardWidth  = settings.cardWidth  || 480;
        var cardGap    = settings.cardGap    || 80;
        var rotation   = settings.rotation   || 35;
        var sideScale  = settings.sideScale  || 0.82;
        var step       = cardWidth + cardGap;
        var zDepth     = cardWidth * 0.3;

        // pos.val is a float used for smooth interpolation
        // targetIndex is always a clean integer — source of truth for snapping
        var pos          = { val: 0 };
        var targetIndex  = 0;
        var isDragging   = false;
        var dragStartX   = 0;
        var dragStartVal = 0;
        var lastX        = 0;
        var velocity     = 0;
        var autoTimer    = null;
        var isEditorMode = window.elementorFrontend && elementorFrontend.isEditMode();

        $track[0].style.perspective       = ( settings.perspective || 1400 ) + 'px';
        $track[0].style.perspectiveOrigin = '50% 50%';

        // ── Card math ───────────────────────────────────────────────────────
        function getOffset( index ) {
            var offset = index - pos.val;
            while ( offset >  numCards / 2 ) offset -= numCards;
            while ( offset < -numCards / 2 ) offset += numCards;
            return offset;
        }

        function updateCards() {
            cards.forEach( function ( card ) {
                var offset    = getOffset( parseInt( card.dataset.index ) );
                var absOffset = Math.abs( offset );

                var x       = offset * step;
                var z       = -absOffset * zDepth;
                var rotY    = offset * rotation;
                var scale   = Math.max( 0.45, 1 - absOffset * ( 1 - sideScale ) );
                var opacity = absOffset > 2.5 ? 0 : Math.max( 0.2, 1 - absOffset * 0.3 );
                var zIndex  = Math.round( 100 - absOffset * 10 );

                gsap.set( card, {
                    x:               x,
                    z:               z,
                    rotationY:       rotY,
                    scale:           scale,
                    opacity:         opacity,
                    zIndex:          zIndex,
                    transformOrigin: '50% 50%',
                    force3D:         true,
                } );
            } );
        }

        // ── Snap to a clean index ────────────────────────────────────────────
        function goTo( index, onDone ) {
            targetIndex = index; // always store clean integer
            gsap.killTweensOf( pos );
            gsap.to( pos, {
                val:        index,
                duration:   settings.duration || 0.75,
                ease:       settings.easing   || 'power2.inOut',
                onUpdate:   updateCards,
                onComplete: onDone || null,
            } );
        }

        // ── Autoplay ─────────────────────────────────────────────────────────
        function startAutoplay() {
            if ( ! settings.autoplay || isEditorMode ) return;
            stopAutoplay();
            autoTimer = setInterval( function () {
                if ( isDragging ) return;
                // Always advance from targetIndex — never from pos.val
                var next = settings.direction === 'right'
                    ? targetIndex - 1
                    : targetIndex + 1;
                goTo( next );
            }, settings.speed || 3000 );
        }

        function stopAutoplay() {
            if ( autoTimer ) { clearInterval( autoTimer ); autoTimer = null; }
        }

        // ── Drag ─────────────────────────────────────────────────────────────
        var stage = $wrapper.find( '.e3dc-stage' )[0];

        if ( settings.draggable !== false ) {

            stage.addEventListener( 'pointerdown', function ( e ) {
                isDragging   = true;
                dragStartX   = e.clientX;
                dragStartVal = pos.val;
                velocity     = 0;
                lastX        = e.clientX;
                stage.setPointerCapture( e.pointerId );
                gsap.killTweensOf( pos );
                stopAutoplay();
                stage.style.cursor = 'grabbing';
            } );

            stage.addEventListener( 'pointermove', function ( e ) {
                if ( ! isDragging ) return;
                velocity = e.clientX - lastX;
                lastX    = e.clientX;
                pos.val  = dragStartVal - ( e.clientX - dragStartX ) / step;
                updateCards();
            } );

            stage.addEventListener( 'pointerup', function () {
                if ( ! isDragging ) return;
                isDragging         = false;
                stage.style.cursor = 'grab';

                // Snap to nearest integer + momentum nudge
                var momentum = -velocity / step * 2.5;
                var snapped  = Math.round( pos.val + momentum );
                goTo( snapped, startAutoplay );
            } );

            stage.addEventListener( 'pointercancel', function () {
                isDragging         = false;
                stage.style.cursor = 'grab';
                goTo( Math.round( pos.val ), startAutoplay );
            } );

        }

        // Pause on hover
        if ( settings.pauseOnHover !== false ) {
            $wrapper[0].addEventListener( 'mouseenter', stopAutoplay );
            $wrapper[0].addEventListener( 'mouseleave', function () {
                if ( ! isDragging ) startAutoplay();
            } );
        }

        // Suppress click during drag
        stage.addEventListener( 'click', function ( e ) {
            if ( Math.abs( pos.val - Math.round( pos.val ) ) > 0.08 ) {
                e.preventDefault();
                e.stopPropagation();
            }
        } );

        // ── Init ─────────────────────────────────────────────────────────────
        updateCards();
        startAutoplay();
    };

    $( window ).on( 'elementor/frontend/init', function () {
        elementorFrontend.hooks.addAction(
            'frontend/element_ready/elematic-threed-carousel.default',
            widget3DCarousel
        );
    } );

} )( jQuery );